const wrapper = document.getElementById('wrapper');
const canvas  = document.getElementById('gameCanvas');
const ctx     = canvas.getContext('2d');

let W, H;
function resize() {
  const vw = window.innerWidth, vh = window.innerHeight;
  const ratio = 16 / 9;
  if (vw / vh > ratio) { H = vh; W = Math.round(H * ratio); }
  else                  { W = vw; H = Math.round(W / ratio); }
  canvas.width  = W;
  canvas.height = H;
  wrapper.style.width  = W + 'px';
  wrapper.style.height = H + 'px';
  document.getElementById('backBtn').style.fontSize = (W * 0.012) + 'px';
  detectSlit(); // recalc slit when resize
}
window.addEventListener('resize', resize);
window.addEventListener('orientationchange', () => setTimeout(resize, 100));

// ── Image Loading ──────────────────────────────────────────────────
function loadImg(src) {
  const img = new Image();
  img.src = src;
  return img;
}
const IMG = {
  ui:  loadImg("images/ui.jpg"),
  bg:  loadImg("images/bg.jpg"),
  r2l: [loadImg("images/r2l_1.png"), loadImg("images/r2l_2.png"), loadImg("images/r2l_3.png")],
  l2r: [loadImg("images/l2r_1.png"), loadImg("images/l2r_2.png"), loadImg("images/l2r_3.png")],
};

// ── Sound Effects ──────────────────────────────────────────────────
const se_click = "data:audio/mpeg;base64,";
const se_hit_1 = "data:audio/mpeg;base64,";
const se_hit_2 = "data:audio/mpeg;base64,";
const se_hit_3 = "data:audio/mpeg;base64,";
const se_hit_4 = "data:audio/mpeg;base64,";
const se_hit_5 = "data:audio/mpeg;base64,";
const se_hit_list = [se_hit_1, se_hit_2, se_hit_3, se_hit_4, se_hit_5];
const clickSoundPool = [];
let clickSoundPoolIndex = 0;
function playClickSound() {
  try {
    if (clickSoundPool.length === 0) {
      for (let i = 0; i < 6; i++) {
        const a = new Audio(se_click);
        a.preload = 'auto';
        clickSoundPool.push(a);
      }
    }
    const a = clickSoundPool[clickSoundPoolIndex];
    clickSoundPoolIndex = (clickSoundPoolIndex + 1) % clickSoundPool.length;
    a.currentTime = 0;
    const p = a.play();
    if (p && typeof p.catch === 'function') p.catch(() => {});
  } catch (err) {}
}


// iPhone / iOS Safari support:
// HTMLAudioElement with data-URI MP3 may stay locked on iPhone until an audio
// context is resumed by a user gesture.  This WebAudio path unlocks the sound
// when a mode button is pressed, then plays the click SE on every tap/click.
let clickAudioCtx = null;
let clickAudioBuffer = null;
let clickAudioLoading = false;
let clickAudioUnlocked = false;

function clickBase64ToArrayBuffer(dataUri) {
  const base64 = dataUri.split(',')[1] || dataUri;
  const binary = atob(base64);
  const len = binary.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) bytes[i] = binary.charCodeAt(i);
  return bytes.buffer;
}

function unlockClickAudio() {
  try {
    const AC = window.AudioContext || window.webkitAudioContext;
    if (!AC) return;
    if (!clickAudioCtx) clickAudioCtx = new AC();
    if (clickAudioCtx.state === 'suspended') clickAudioCtx.resume().catch(() => {});

    // Play a silent one-sample buffer during the user gesture to unlock iOS audio.
    if (!clickAudioUnlocked) {
      const silent = clickAudioCtx.createBuffer(1, 1, 22050);
      const src = clickAudioCtx.createBufferSource();
      src.buffer = silent;
      src.connect(clickAudioCtx.destination);
      src.start(0);
      clickAudioUnlocked = true;
    }

    if (!clickAudioBuffer && !clickAudioLoading) {
      clickAudioLoading = true;
      const arr = clickBase64ToArrayBuffer(se_click);
      clickAudioCtx.decodeAudioData(arr.slice(0), (buf) => {
        clickAudioBuffer = buf;
        clickAudioLoading = false;
      }, () => {
        clickAudioLoading = false;
      });
    }
    ensureHitAudioLoaded();
  } catch (err) {}
}

function playClickSoundWebAudio() {
  try {
    unlockClickAudio();
    if (clickAudioCtx && clickAudioBuffer) {
      const src = clickAudioCtx.createBufferSource();
      src.buffer = clickAudioBuffer;
      src.connect(clickAudioCtx.destination);
      src.start(0);
      return true;
    }
  } catch (err) {}
  return false;
}

// Override the earlier HTMLAudio version with a WebAudio-first version.
function playClickSound() {
  if (playClickSoundWebAudio()) return;

  // Fallback for browsers where WebAudio decoding is not available yet.
  try {
    if (clickSoundPool.length === 0) {
      for (let i = 0; i < 6; i++) {
        const a = new Audio(se_click);
        a.preload = 'auto';
        a.load();
        clickSoundPool.push(a);
      }
    }
    const a = clickSoundPool[clickSoundPoolIndex];
    clickSoundPoolIndex = (clickSoundPoolIndex + 1) % clickSoundPool.length;
    a.currentTime = 0;
    const p = a.play();
    if (p && typeof p.catch === 'function') p.catch(() => {});
  } catch (err) {}
}


// Hit combo sounds: 1hit, 2hit, 3hit, 4hit, and 5hit+.
let hitAudioBuffers = new Array(5).fill(null);
let hitAudioLoading = new Array(5).fill(false);
const hitSoundPools = [[], [], [], [], []];
const hitSoundPoolIndex = [0, 0, 0, 0, 0];

function ensureHitAudioLoaded() {
  try {
    if (!clickAudioCtx) return;
    for (let i = 0; i < se_hit_list.length; i++) {
      if (hitAudioBuffers[i] || hitAudioLoading[i]) continue;
      hitAudioLoading[i] = true;
      const arr = clickBase64ToArrayBuffer(se_hit_list[i]);
      clickAudioCtx.decodeAudioData(arr.slice(0), (buf) => {
        hitAudioBuffers[i] = buf;
        hitAudioLoading[i] = false;
      }, () => {
        hitAudioLoading[i] = false;
      });
    }
  } catch (err) {}
}

function playHitSound(hitCount) {
  const idx = Math.min(Math.max(hitCount, 1), 5) - 1;
  try {
    unlockClickAudio();
    ensureHitAudioLoaded();
    if (clickAudioCtx && hitAudioBuffers[idx]) {
      const src = clickAudioCtx.createBufferSource();
      src.buffer = hitAudioBuffers[idx];
      src.connect(clickAudioCtx.destination);
      src.start(0);
      return;
    }
  } catch (err) {}

  // Fallback for browsers where WebAudio decoding is not ready yet.
  try {
    if (hitSoundPools[idx].length === 0) {
      for (let i = 0; i < 4; i++) {
        const a = new Audio(se_hit_list[idx]);
        a.preload = 'auto';
        a.load();
        hitSoundPools[idx].push(a);
      }
    }
    const pool = hitSoundPools[idx];
    const a = pool[hitSoundPoolIndex[idx]];
    hitSoundPoolIndex[idx] = (hitSoundPoolIndex[idx] + 1) % pool.length;
    a.currentTime = 0;
    const p = a.play();
    if (p && typeof p.catch === 'function') p.catch(() => {});
  } catch (err) {}
}

// Unlock as early as possible on iPhone. These are harmless on PC.
document.addEventListener('touchstart', unlockClickAudio, { once: true, passive: true });
document.addEventListener('pointerdown', unlockClickAudio, { once: true, passive: true });
document.addEventListener('click', unlockClickAudio, { once: true });

// ── Slit Detection ─────────────────────────────────────────────────
// The UI image has a vertical black stripe (the scope slit) at the center.
// We scan a horizontal line at vertical midpoint to find the leftmost and
// rightmost fully-black pixels, then store as canvas-relative values.
let slitX = 0, slitW = 0;

function detectSlit() {
  if (!IMG.ui.complete || !IMG.ui.naturalWidth) return;
  const iw = IMG.ui.naturalWidth;
  const ih = IMG.ui.naturalHeight;
  const oc  = document.createElement('canvas');
  oc.width  = iw; oc.height = ih;
  const oc2 = oc.getContext('2d');
  oc2.drawImage(IMG.ui, 0, 0);

  // Scan multiple rows near the top third to find the slit reliably
  let x0 = iw, x1 = -1;
  for (let scanY = Math.floor(ih * 0.1); scanY < Math.floor(ih * 0.5); scanY += 10) {
    const row = oc2.getImageData(0, scanY, iw, 1).data;
    for (let x = 0; x < iw; x++) {
      const r = row[x*4], g = row[x*4+1], b = row[x*4+2];
      if (r < 20 && g < 20 && b < 20) {
        if (x < x0) x0 = x;
        if (x > x1) x1 = x;
      }
    }
  }

  if (x1 >= x0 && x0 < iw) {
    slitX = (x0 / iw) * W;
    slitW = ((x1 - x0 + 1) / iw) * W;
    console.log('Slit px:', x0, x1, '-> canvas px:', slitX.toFixed(1), slitW.toFixed(1));
  }
}

IMG.ui.onload = () => { resize(); detectSlit(); };

// ── Game State ─────────────────────────────────────────────────────
let gameMode = null;
let score = 0, hiScore = 0;
let hiScoreTime = '';
let gameRunning = false;
let target = null, spawnTimer = null;
let targets = [];
let expertChainTimer = null;
let expertChainActive = false;
let expertChainDirection = null;
let hitFlash = 0, missFlash = 0;
let streakBroken = false;  // true after miss/pass, score shows blank until next hit
let postHitGuardUntil = 0;
let hiScoreId = '';
const modeHiScores = { left: 0, right: 0, oni: 0, expert: 0 };
const modeHiScoreTimes = { left: '', right: '', oni: '', expert: '' };
const modeHiScoreIds = { left: '', right: '', oni: '', expert: '' };

function loadModeHiScore(mode) {
  hiScore = modeHiScores[mode] || 0;
  hiScoreTime = modeHiScoreTimes[mode] || '';
  hiScoreId = modeHiScoreIds[mode] || '';
}

function saveModeHiScore(mode) {
  modeHiScores[mode] = hiScore;
  modeHiScoreTimes[mode] = hiScoreTime;
  modeHiScoreIds[mode] = hiScoreId;
}

function pad2(n) { return String(n).padStart(2,'0'); }

function getDisplayHour(d) {
  const h = d.getHours();
  return h === 0 ? 24 : h;
}

function getNowStr() {
  const d = new Date();
  return d.getFullYear() + '/' + (d.getMonth()+1) + '/' + d.getDate() + '/' + pad2(getDisplayHour(d)) + ':' + pad2(d.getMinutes());
}

function getTimeNum() {
  const d = new Date();
  return getDisplayHour(d) * 100 + d.getMinutes();
}

function generateId(sc) {
  const letters = ['A','B','C'];
  const mult    = [2, 3, 4];
  const sub     = [1, 2, 3];
  const i1 = Math.floor(Math.random() * 3);
  const i2 = Math.floor(Math.random() * 3);
  const t  = getTimeNum();
  const val = (sc * t) * mult[i1] - sub[i2];
  return 'iD:' + letters[i1] + letters[i2] + val;
}

// Original image dimensions
const ORIG_W = 1920, ORIG_H = 1080;

// Hit detection now uses the actual non-transparent pixels of the target PNGs.
// The uploaded JPG-style black background has been converted to transparent PNG data URLs above.
const HIT_ALPHA_THRESHOLD = 32;
const HIT_RADIUS_ORIG = 2; // crosshair + target opaque-pixel hit area, 1px further inside

function getScale() { return W / ORIG_W; }

function getAimCenterX() {
  // Use the centre of the detected UI slit/crosshair instead of assuming W/2.
  // Fallback remains W/2 until the UI image has finished loading.
  return slitW > 0 ? slitX + slitW / 2 : W / 2;
}

function getAimCenterY() {
  return H / 2;
}

function getTargetMask(img) {
  if (img._hitMask) return img._hitMask;
  const iw = img.naturalWidth || ORIG_W;
  const ih = img.naturalHeight || ORIG_H;
  const oc = document.createElement('canvas');
  oc.width = iw; oc.height = ih;
  const oc2 = oc.getContext('2d', { willReadFrequently: true });
  oc2.drawImage(img, 0, 0, iw, ih);
  const data = oc2.getImageData(0, 0, iw, ih).data;

  // Find the actual opaque character area. This prevents the full 16:9 image
  // from being treated as the spawn boundary, so the next target appears quickly.
  let minX = iw, minY = ih, maxX = -1, maxY = -1;
  for (let y = 0; y < ih; y++) {
    for (let x = 0; x < iw; x++) {
      const a = data[(y * iw + x) * 4 + 3];
      if (a > HIT_ALPHA_THRESHOLD) {
        if (x < minX) minX = x;
        if (y < minY) minY = y;
        if (x > maxX) maxX = x;
        if (y > maxY) maxY = y;
      }
    }
  }
  if (maxX < 0) { minX = 0; minY = 0; maxX = iw - 1; maxY = ih - 1; }

  img._hitMask = { w: iw, h: ih, data, bounds: { minX, minY, maxX, maxY } };
  return img._hitMask;
}

function hasOpaquePixelNear(mask, x, y, radius) {
  const cx = Math.round(x);
  const cy = Math.round(y);
  const r = Math.max(0, radius | 0);
  for (let yy = cy - r; yy <= cy + r; yy++) {
    if (yy < 0 || yy >= mask.h) continue;
    for (let xx = cx - r; xx <= cx + r; xx++) {
      if (xx < 0 || xx >= mask.w) continue;
      const a = mask.data[(yy * mask.w + xx) * 4 + 3];
      if (a > HIT_ALPHA_THRESHOLD) return true;
    }
  }
  return false;
}

// ── Spawn ──────────────────────────────────────────────────────────
function createTarget(actualMode) {
  const sc     = getScale();
  const imgW   = ORIG_W * sc;
  const imgH   = ORIG_H * sc;
  const SPEED  = W / 6;

  let imgs, startImgLeft, direction;
  const idx = Math.floor(Math.random() * 3);

  if (actualMode === 'right') {
    // R→L: character starts from the right side
    imgs = IMG.r2l;
    direction = -1;
  } else {
    // L→R: character starts from the left side
    imgs = IMG.l2r;
    direction = 1;
  }

  const mask = getTargetMask(imgs[idx]);
  // Spawn position is randomized between two points.
  // R→L: character's left edge starts at 75% or 60% of the screen width.
  // L→R: character's right edge starts at 25% or 40% of the screen width.
  const spawnRatio = Math.random() < 0.5 ? 0.75 : 0.60;
  const rightSpawnX = W * spawnRatio;
  const leftSpawnX  = W * (1 - spawnRatio);
  if (direction === -1) {
    startImgLeft = rightSpawnX - mask.bounds.minX * sc;
  } else {
    startImgLeft = leftSpawnX - mask.bounds.maxX * sc;
  }

  return {
    img: imgs[idx],
    mask,
    imgW, imgH,
    imageLeft: startImgLeft,
    direction,
    speed: SPEED,
    passed: false,
  };
}

function spawnTarget() {
  const actualMode = gameMode === 'oni' ? (Math.random() < 0.5 ? 'right' : 'left') : gameMode;
  target = createTarget(actualMode);
}

function clearSpawnTimers() {
  if (spawnTimer) {
    clearTimeout(spawnTimer);
    spawnTimer = null;
  }
  if (expertChainTimer) {
    clearTimeout(expertChainTimer);
    expertChainTimer = null;
  }
}

function scheduleSpawn() {
  clearSpawnTimers();
  const delay = (0.2 + 0.1 + Math.random() * 0.4) * 1000;
  spawnTimer = setTimeout(() => {
    spawnTimer = null;
    if (gameMode === 'expert') spawnExpertWave();
    else spawnTarget();
  }, delay);
}

function spawnExpertWave() {
  targets = [];
  target = null;
  expertChainDirection = Math.random() < 0.5 ? 'right' : 'left';
  expertChainActive = true;
  spawnExpertTarget(expertChainDirection);
  scheduleExpertChainDecision();
}

function spawnExpertTarget(directionMode) {
  targets.push(createTarget(directionMode));
}

function scheduleExpertChainDecision() {
  if (gameMode !== 'expert' || !gameRunning || !expertChainActive) return;

  // Spawn additional target from the same direction in 0.3-0.6 seconds (50% chance)
  // The next random left/right spawn won't start until the additional spawn ends.
  if (Math.random() < 0.5) {
    const delay = (0.5 + Math.random() * 0.1) * 1000;
    expertChainTimer = setTimeout(() => {
      expertChainTimer = null;
      if (gameMode !== 'expert' || !gameRunning || !expertChainActive) return;
      spawnExpertTarget(expertChainDirection);
      scheduleExpertChainDecision();
    }, delay);
  } else {
    expertChainActive = false;
    expertChainDirection = null;
    if (targets.length === 0) scheduleSpawn();
  }
}

// ── Hit Check ─────────────────────────────────────────────────────
function isTargetAtCenter(t = target) {
  if (!t) return false;
  const sc = getScale();
  const srcX = (getAimCenterX() - t.imageLeft) / sc;
  const srcY = getAimCenterY() / sc;
  if (srcX < 0 || srcX >= t.mask.w || srcY < 0 || srcY >= t.mask.h) return false;
  return hasOpaquePixelNear(t.mask, srcX, srcY, HIT_RADIUS_ORIG);
}

function getActiveTargets() {
  return gameMode === 'expert' ? targets : (target ? [target] : []);
}

// ── Input ──────────────────────────────────────────────────────────
function handleTap(e) {
  updateSmallScreenGuard();
  if (isTooSmallForPcPlay()) return;
  if (!gameRunning) return;
  if (!e.isTrusted) return;
  e.preventDefault();
  playClickSound();

  const activeTargets = getActiveTargets();
  // Mismatched clicks are treated as errors only when no targets are left immediately after a successful hit.
  // However, in Expert mode, if other targets remain, check the next target as usual.
  if (activeTargets.length === 0) {
    if (performance.now() < postHitGuardUntil) {
      streakBroken = true;
      missFlash = 14;
      postHitGuardUntil = 0;
    }
    return;
  }

  const hitIndex = activeTargets.findIndex(t => isTargetAtCenter(t));
  if (hitIndex >= 0) {
    if (streakBroken) { score = 1; streakBroken = false; }
    else score++;
    playHitSound(score);
    if (score > hiScore) {
      hiScore = score;
      hiScoreTime = getNowStr();
      hiScoreId   = generateId(score);
      saveModeHiScore(gameMode);
    }
    hitFlash = 14;

    if (gameMode === 'expert') {
      const hitTarget = activeTargets[hitIndex];
      const idx = targets.indexOf(hitTarget);
      if (idx >= 0) targets.splice(idx, 1);
      if (targets.length === 0 && !expertChainActive) {
        postHitGuardUntil = performance.now() + 160;
        scheduleSpawn();
      }
    } else {
      target = null;
      postHitGuardUntil = performance.now() + 160;
      scheduleSpawn();
    }
  } else {
    streakBroken = true;
    missFlash = 14;
  }
}
canvas.addEventListener('mousedown', handleTap);
canvas.addEventListener('touchstart', handleTap, { passive: false });

// ── Game Loop ──────────────────────────────────────────────────────
let lastTime = null;
function gameLoop(ts) {
  updateSmallScreenGuard();
  if (!gameRunning) return;
  if (!lastTime) lastTime = ts;
  const dt = Math.min((ts - lastTime) / 1000, 0.05);
  lastTime = ts;

  const activeTargets = getActiveTargets();
  if (activeTargets.length > 0) {
    const sc = getScale();
    const blackLeft = slitW > 0 ? slitX : W / 2;
    const blackRight = slitW > 0 ? slitX + slitW : W / 2;

    for (let i = activeTargets.length - 1; i >= 0; i--) {
      const t = activeTargets[i];
      t.imageLeft += t.direction * t.speed * dt;
      const charLeft  = t.imageLeft + t.mask.bounds.minX * sc;
      const charRight = t.imageLeft + t.mask.bounds.maxX * sc;
      // Out of boundary detection occurs when the opaque part of the character completely passes the center black zone.
      // For Right to Left, it's out when the right edge of the character passes the left edge of the black zone.
      // For Left to Right, it's out when the left edge of the character passes the right edge of the black zone.
      const passedBlackZone = t.direction === -1 ? charRight < blackLeft
                                                  : charLeft > blackRight;
      if (passedBlackZone && !t.passed) {
        t.passed = true;
        streakBroken = true;
        missFlash = 20;
        if (gameMode === 'expert') {
          const idx = targets.indexOf(t);
          if (idx >= 0) targets.splice(idx, 1);
        } else {
          target = null;
        }
      }
    }

    if (gameMode === 'expert' && targets.length === 0 && !expertChainActive) {
      scheduleSpawn();
    } else if (gameMode !== 'expert' && !target) {
      scheduleSpawn();
    }
  }

  draw();
  if (hitFlash  > 0) hitFlash--;
  if (missFlash > 0) missFlash--;
  requestAnimationFrame(gameLoop);
}

// ── Draw ───────────────────────────────────────────────────────────
function draw() {
  ctx.clearRect(0, 0, W, H);

  // 1. Background (bottom layer)
  ctx.drawImage(IMG.bg, 0, 0, W, H);

  // 2. Target — clipped to slit only, black removed via 'screen'
  const drawTargets = getActiveTargets();
  if (drawTargets.length > 0 && slitW > 0) {
    ctx.save();
    ctx.beginPath();
    ctx.rect(slitX, 0, slitW, H);
    ctx.clip();
    ctx.globalCompositeOperation = 'screen';
    for (const t of drawTargets) {
      ctx.drawImage(t.img, t.imageLeft, 0, t.imgW, t.imgH);
    }
    ctx.restore();
  }

  // 3. UI overlay — drawn OPAQUE everywhere EXCEPT the slit
  //    We draw left portion and right portion, skipping the slit gap.
  if (slitW > 0) {
    const sx = slitX, sw = slitW;
    // Left of slit
    if (sx > 0) {
      ctx.save();
      ctx.beginPath();
      ctx.rect(0, 0, sx, H);
      ctx.clip();
      ctx.drawImage(IMG.ui, 0, 0, W, H);
      ctx.restore();
    }
    // Right of slit
    const rx = sx + sw;
    if (rx < W) {
      ctx.save();
      ctx.beginPath();
      ctx.rect(rx, 0, W - rx, H);
      ctx.clip();
      ctx.drawImage(IMG.ui, 0, 0, W, H);
      ctx.restore();
    }
    // Slit area: draw UI with screen blend so the crosshair dot (white pixel) shows
    // but the black background of the slit stays invisible
    ctx.save();
    ctx.beginPath();
    ctx.rect(sx, 0, sw, H);
    ctx.clip();
    ctx.globalCompositeOperation = 'screen';
    ctx.drawImage(IMG.ui, 0, 0, W, H);
    ctx.restore();
  } else {
    // Fallback before slit detected
    ctx.save();
    ctx.globalCompositeOperation = 'screen';
    ctx.drawImage(IMG.ui, 0, 0, W, H);
    ctx.restore();
  }

  // 4. Score UI (drawn on top of everything)
  const fs      = W * 0.035;
  const fsSmall = W * 0.018;

  // Current score — top center
  ctx.save();
  ctx.font        = `bold ${fs}px Arial`;
  ctx.textAlign   = 'center';
  ctx.fillStyle   = hitFlash > 0 ? '#00ff88' : missFlash > 0 ? '#ff4444' : '#ffffff';
  ctx.shadowColor = hitFlash > 0 ? '#00ff88' : missFlash > 0 ? '#ff3333' : 'transparent';
  ctx.shadowBlur  = hitFlash > 0 || missFlash > 0 ? 18 : 0;
  ctx.fillText(score, W / 2, H * 0.07);
  ctx.restore();

  // Current date/time — top left
  ctx.save();
  ctx.font        = `${fsSmall}px Arial`;
  ctx.textAlign   = 'left';
  ctx.fillStyle   = 'rgba(255,255,255,0.82)';
  ctx.shadowColor = 'rgba(255,255,255,0.55)';
  ctx.shadowBlur  = 4;
  ctx.fillText(getNowStr(), W * 0.03, H * 0.06);
  ctx.restore();

  // Hi score — top right
  ctx.save();
  ctx.font        = `${fsSmall}px Arial`;
  ctx.textAlign   = 'right';
  ctx.fillStyle   = '#ffd700';
  ctx.shadowColor = '#ffd700';
  ctx.shadowBlur  = 6;
  ctx.fillText('BEST: ' + hiScore, W * 0.97, H * 0.06);

  ctx.font        = `${fsSmall * 0.72}px Arial`;
  ctx.fillStyle   = 'rgba(255,215,0,0.86)';
  ctx.shadowBlur  = 4;
  if (hiScoreTime) ctx.fillText(hiScoreTime, W * 0.97, H * 0.085);
  if (hiScoreId)   ctx.fillText(hiScoreId,   W * 0.97, H * 0.108);
  ctx.restore();

  // Mode label — upper right area
  if (gameMode === 'oni') {
    ctx.save();
    ctx.font        = `bold ${fsSmall}px Arial`;
    ctx.textAlign   = 'right';
    ctx.fillStyle   = '#8a5cff';
    ctx.shadowColor = '#8a5cff';
    ctx.shadowBlur  = 10;
    ctx.fillText('Demon', W * 0.97, H * 0.145);
    ctx.restore();
  } else if (gameMode === 'expert') {
    ctx.save();
    ctx.font        = `bold ${fsSmall}px Arial`;
    ctx.textAlign   = 'right';
    ctx.fillStyle   = '#8a5cff';
    ctx.shadowColor = '#8a5cff';
    ctx.shadowBlur  = 10;
    ctx.fillText('Expert', W * 0.97, H * 0.145);
    ctx.restore();
  }
}





// ── PC Small Screen Guard ──────────────────────────────────────────
function isPcLikeViewport() {
  return window.matchMedia && window.matchMedia('(pointer: fine)').matches;
}

function isTooSmallForPcPlay() {
  return isPcLikeViewport() && (window.innerWidth <= 1000 || window.innerHeight <= 500);
}

function updateSmallScreenGuard() {
  const overlay = document.getElementById('smallScreenOverlay');
  if (!overlay) return;
  const blocked = isTooSmallForPcPlay();
  overlay.style.display = blocked ? 'flex' : 'none';

  if (blocked) {
    gameRunning = false;
    target = null;
    targets = [];
    postHitGuardUntil = 0;
    expertChainActive = false;
    expertChainDirection = null;
    clearSpawnTimers();
    const backBtn = document.getElementById('backBtn'); if (backBtn) backBtn.style.display = 'none';
    const shareBtn = document.getElementById('shareScoreBtn'); if (shareBtn) shareBtn.style.display = 'none';
    const menu = document.getElementById('menuScreen'); if (menu) menu.style.display = 'none';
  }
}

function backFromSmallScreen() {
  gameRunning = false;
  target = null;
  targets = [];
  postHitGuardUntil = 0;
  expertChainActive = false;
  expertChainDirection = null;
  clearSpawnTimers();
  const backBtn = document.getElementById('backBtn'); if (backBtn) backBtn.style.display = 'none';
  const shareBtn = document.getElementById('shareScoreBtn'); if (shareBtn) shareBtn.style.display = 'none';

  if (isTooSmallForPcPlay()) {
    const menu = document.getElementById('menuScreen'); if (menu) menu.style.display = 'none';
  } else {
    const menu = document.getElementById('menuScreen'); if (menu) menu.style.display = 'flex';
  }
  updateSmallScreenGuard();
}

// ── Virtual Online Count ───────────────────────────────────────────
let onlineAverage = 88 + Math.floor(Math.random() * 45);
let onlineCount = onlineAverage;
let onlineTimer = null;

function updateOnlineCountDisplay() {
  const el = document.getElementById('onlineCount');
  if (el) el.textContent = onlineCount;
}

function chooseOnlineDirection() {
  if (onlineCount <= onlineAverage - 30) return Math.random() < 0.82 ? 1 : -1;
  if (onlineCount >= onlineAverage + 50) return Math.random() < 0.82 ? -1 : 1;
  return Math.random() < 0.5 ? 1 : -1;
}

function tickOnlineCount() {
  const amount = 1 + Math.floor(Math.random() * 4);
  const direction = chooseOnlineDirection();
  onlineCount = Math.max(1, onlineCount + direction * amount);
  updateOnlineCountDisplay();
  scheduleOnlineCountTick();
}

function scheduleOnlineCountTick() {
  if (onlineTimer) clearTimeout(onlineTimer);
  const delays = [15000, 20000, 30000];
  const delay = delays[Math.floor(Math.random() * delays.length)];
  onlineTimer = setTimeout(tickOnlineCount, delay);
}

updateOnlineCountDisplay();
scheduleOnlineCountTick();

