// ── Score Verification ─────────────────────────────────────────────
function openScoreCheckPanel() {
  const panel = document.getElementById('scoreCheckPanel');
  if (!panel) return;
  panel.style.display = 'block';
  const result = document.getElementById('verifyResult');
  const progress = document.getElementById('verifyProgress');
  if (result) {
    result.textContent = '';
    result.className = 'verify-result';
  }
  if (progress) {
    progress.classList.remove('run');
    progress.style.display = 'none';
  }
}

function closeScoreCheckPanel() {
  const panel = document.getElementById('scoreCheckPanel');
  if (panel) panel.style.display = 'none';
}

function isValidTimeCodeForId(t) {
  if (!Number.isInteger(t)) return false;
  const h = Math.floor(t / 100);
  const m = t % 100;
  return h >= 1 && h <= 24 && m >= 0 && m <= 59;
}

function verifyScoreId(score, idText) {
  const id = String(idText || '').trim().toUpperCase();
  const m = id.match(/^(?:ID:)?([ABC])([ABC])(-?\d+)$/);
  if (!Number.isFinite(score) || score <= 0 || !Number.isInteger(score) || !m) return false;

  const multMap = { A: 2, B: 3, C: 4 };
  const subMap = { A: 1, B: 2, C: 3 };
  const first = m[1];
  const second = m[2];
  const idNum = Number(m[3]);
  const base = idNum + subMap[second];
  const divisor = score * multMap[first];

  if (!Number.isInteger(idNum) || divisor <= 0 || base % divisor !== 0) return false;

  const timeCode = base / divisor;
  return isValidTimeCodeForId(timeCode);
}

function runScoreVerification() {
  const scoreInput = document.getElementById('verifyScoreInput');
  const idInput = document.getElementById('verifyIdInput');
  const progress = document.getElementById('verifyProgress');
  const result = document.getElementById('verifyResult');
  if (!scoreInput || !idInput || !progress || !result) return;

  result.textContent = '';
  result.className = 'verify-result';
  progress.style.display = 'block';
  progress.classList.remove('run');
  void progress.offsetWidth;
  progress.classList.add('run');

  const score = Number(scoreInput.value);
  const idText = idInput.value;

  setTimeout(() => {
    const ok = verifyScoreId(score, idText);
    result.className = ok ? 'verify-result ok' : 'verify-result ng';
    result.textContent = ok ? 'verify ✓' : 'Verification failed';
  }, 1100);
}

// ── Menu Control ───────────────────────────────────────────────────
function startGame(mode) {
  updateSmallScreenGuard();
  if (isTooSmallForPcPlay()) return;
  unlockClickAudio();
  gameMode = mode; score = 0; gameRunning = true;
  loadModeHiScore(mode);
  const menu = document.getElementById('menuScreen'); if (menu) menu.style.display = 'none';
  const backBtn = document.getElementById('backBtn'); if (backBtn) backBtn.style.display = 'block';
  const shareBtn = document.getElementById('shareScoreBtn'); if (shareBtn) shareBtn.style.display = 'block';
  lastTime = null; target = null; targets = [];
  postHitGuardUntil = 0;
  expertChainActive = false; expertChainDirection = null;
  clearSpawnTimers();
  scheduleSpawn();
  requestAnimationFrame(gameLoop);
}

function goMenu() {
  window.location.href = 'index.html';
}

