updateSmallScreenGuard();

// Auto-start game if mode is defined
if (window.GAME_MODE) {
  const checkLoad = () => {
    if (IMG.bg.complete) {
      startGame(window.GAME_MODE);
    } else {
      setTimeout(checkLoad, 50);
    }
  };
  checkLoad();
}
